import React from "react";

import { Box } from "@mui/material";
import { Cursor, Typewriter } from "react-simple-typewriter";

function TextEffext() {
  return (
    <Box
      sx={{
        letterSpacing: 4,
        m: 1,
        fontFamily: "Monospace",
        textAlign: "left",
        fontWeight: "bold",
        textTransform: "capitalize",
      }}
    >
      {""}
      <span>
        <Typewriter
          words={[
            "Ciao!",
            "Sasa!",
            "Bonjour!",
            "Hola!",
            "こんにちは！",
            "Привіт!",
            "હેલો ત્યાં!",
          ]}
          loop={5}
          cursor
          cursorStyle="_"
          typeSpeed={70}
          deleteSpeed={50}
          delaySpeed={1000}
        />
      </span>
      <span style={{ color: "green" }}>
        <Cursor />
      </span>
    </Box>
  );
}

export default TextEffext;
